// Declare variables
var message = "Hello, World!";
let number = 42;
const pi = 3.14;

// Output variables
// console.log outputs content to the console
console.log(message);
console.log(number);
console.log(pi);

// Conditional
if (number > 0) {
    console.log("This is a positive number");
} else {
    console.log("Not a positive number");
}

// Loop
for (let i = 0; i < 5; i++) {
    console.log("This is iteration " + i);
}

// Array
let fruits = ["Apple", "Banana", "Orange"];
fruits.forEach(function(fruit) {
    console.log("I like eating " + fruit);
});

// Function
function greet(name) {
    return "Hi, " + name + "!";
}
console.log(greet("Ray"));

// OOP
class Person {
    constructor(name, age) {
        this.name = name;
        this.age = age;
    }

    introduce() {
        return "My name is " + this.name + ", I'm " + this.age + " years old.";
    }
}
let person = new Person("Ray", 30);
console.log(person.introduce());

// Exception handling
try {
    let result = number / 0; // Produces Infinity
    console.log(result);
} catch (error) {
    console.error("Error: " + error.message);
} finally {
    console.log("Program execution finished");
}
